import { reactive } from 'vue'
import { user } from '@/api/user'
import { showToast } from '@/components/ToastMessage'

export function useNickname() {
  const state = reactive({
    value: '',
    loading: false,
    error: ''
  })

  // 昵称验证规则
  const validateNickname = (nickname) => {
    // 长度检查：4-8个字符
    if (nickname.length < 4 || nickname.length > 8) {
      return '昵称长度需要在4-8个字符之间'
    }

    // 字符类型检查：只允许中文、数字、英文字母
    if (!/^[\u4e00-\u9fa5a-zA-Z0-9]+$/.test(nickname)) {
      return '昵称只能包含中文、数字、英文字母'
    }

    return ''
  }

  const handleUpdate = async () => {
    // 验证昵称
    const error = validateNickname(state.value)
    if (error) {
      state.error = error
      return false
    }

    state.loading = true
    state.error = ''

    try {
      await user.updateNickname({ username: state.value })
      showToast('昵称修改成功', 'success')
      return true
    } catch (error) {
      showToast(error.response?.data?.message || '修改失败', 'error')
      return false
    } finally {
      state.loading = false
    }
  }

  return {
    state,
    handleUpdate
  }
}
